这里添加一个userlist 记录通讯用户名称，然后用户发送一个join给软件端，软件就把用户名记录下来。
主程序中另开一个线程，定时像这个列表中的所有用户发送消息。
userlist = []


class msg_deal(threading.Thread):
    def __init__(self):
        threading.Thread.__init__(self)

    def run(self):
        try:
            while 1:
                itchat.configured_reply()
                time.sleep(.1)
        except KeyboardInterrupt:
            print('Bye~')


class msg_send(threading.Thread):
    def __init__(self, userlist, stcd, stname):
        threading.Thread.__init__(self)
        self._userlist = userlist
        self.stcd = stcd
        self.stname = stname
        self.warning_time = {}
        for st in stcd:
            self.warning_time[st] = '2016-01-01 0:00:00'

    def run(self):
        connect = sqlite3.connect('data.db3')
        cursor = connect.cursor()
        sql = ("SELECT MAX(TM),Z FROM ST_RIVER_R WHERE STCD = ?")
        while True:
            warn_msg = []
            for key in self.stcd:
                try:
                    cursor.execute(sql, (key,))
                    info = cursor.fetchone()
                except BaseException as err:
                    print('SQL语句执行错误:', err)
                else:
                    water_time = info[0]
                    water = info[1]
                    if water > self.stcd[key] and water_time > self.warning_time[key]:
                        warn_msg.append(water_time + self.stname[key] + '%sm' % water)
                        self.warning_time[key] = water_time
            for _msg in warn_msg:
                for item in self._userlist:
                    itchat.send_msg(_msg, item)
            time.sleep(30)


@itchat.msg_register(['Text', 'Map', 'Card', 'Note', 'Sharing'])
def text_reply(msg):
    if 'quit' in msg['Text']:
        userlist.remove(msg['FromUserName'])
    elif 'join' in msg['Text']:
        userlist.append(msg['FromUserName'])
    else:
        itchat.send('%s' % msg['Text'], msg['FromUserName'])


@itchat.msg_register(['Picture', 'Recording', 'Attachment', 'Video'])
def download_files(msg):
    fileDir = '%s%s' % (msg['Type'], int(time.time()))
    msg['Text'](fileDir)
    itchat.send('%s received' % msg['Type'], msg['FromUserName'])
    itchat.send('@%s@%s' % ('img' if msg['Type'] == 'Picture' else 'fil', fileDir), msg['FromUserName'])


@itchat.msg_register('Friends')
def add_friend(msg):
    itchat.add_friend(**msg['Text'])
    itchat.get_contract()
    itchat.send_msg('Nice to meet you!', msg['RecommendInfo']['UserName'])


@itchat.msg_register('Text', isGroupChat=True)
def text_reply(msg):
    if msg['isAt']:
        if 'join' in msg['Content']:
            userlist.append(msg['FromUserName'])
        elif 'quit' in msg['Content']:
            userlist.remove(msg['FromUserName'])
