            itchat.send(u'@%s\u2005I received: %s' % (msg['ActualNickName'], msg['Content']), msg['FromUserName'])


if __name__ == '__main__':
    itchat.auto_login(hotReload=True)
    print('开始自动回复')
    stcd = {'00010001': 4.4, '00010002': 4.6, '00010003': 4.4}
    stname = {'00010001': '奥运桥', '00010002': '三联桥', '00010003': '东风河桥'}
    _msg_deal = msg_deal()
    _msg_send = msg_send(userlist=userlist, stcd=stcd, stname=stname)
    _msg_deal.start()
    _msg_send.start()
    _msg_deal.join()
    _msg_send.join()

