Here's the code I use to get a rolling timeout on a long download, modified to be independent of the rest of my codebase. This is based on treq's built in collect implementation, and while I'm pretty confident it should work, I haven't tested the download_file here by itself without the rest of my codebase, and have just taken it out of the treq.collect example.

```python

import treq
from functools import partial
from twisted.web.client import ResponseFailed

class WatchfulBodyCollector(Protocol):
    def __init__(self, finished, collector, chunktimeout):
        self.latest_tick = 0
        self.chunktimeout = chunktimeout
        self.finished = finished
        self.collector = collector

    def dataReceived(self, data):
        self.collector(data)
        if self.chunktimeout is not None:
            self.latest_tick += 1
            reactor.callLater(self.chunktimeout, self.checkTimeout,
                                       self.latest_tick)

    def checkTimeout(self, tick):
        if tick == self.latest_tick:
            # We've really timed out.
            self.transport.loseConnection()

    def connectionLost(self, reason):
        self.latest_tick = 0
        if reason.check(ResponseDone):
            self.finished.callback(None)
        elif reason.check(PotentialDataLoss):
            # http://twistedmatrix.com/trac/ticket/4840
            self.finished.callback(None)
        else:
            self.finished.errback(reason)


def watchful_collect(response, collector, chunktimeout=None):
    if response.length == 0:
        return succeed(None)

    d = Deferred()
    response.deliverBody(WatchfulBodyCollector(d, collector, chunktimeout))
    return d


def download_file(reactor, url, destination_filename):
    # The partial here keeps it compatible with treq.collect if you want to switch back
    #collectmethod = treq.collect
    collectmethod = partial(watchful_collect, chunktimeout=10) 
    destination = open(destination_filename, 'wb')
    d = treq.get(url)
    d.addCallback(collectmethod, destination.write)
    d.addBoth(lambda _: destination.close())
    def _retry_hook(failure):
        failure.trap(ResponseFailed)
        print("At Retry Hook")
    d.addErrback(_retry_hook)
    return d

```

