Another hack (or "performance tweak") which should work for your case without breaking the one-acl-per-resource paradigm, is to make the `__acl__` a generator so that if an earlier ACE "hits", the remainder of the ACL need not be computed.:
```
from cornice import Service
from pyramid.decorator import reify
from pyramid.security import Allow, Everyone, DENY_ALL

class UserResource(object):
    def __init__(self, request):
        self.request = request

    @property  # (the property decorator is unnecessary for pyramid >= 1.5)
    def __acl__(self):
        yield Allow, Everyone, 'view'
        for acl in self._acl_heavy:
            yield acl

    @reify
    def _acl_heavy(self):
        # compute and return the db-intenstive tail part of the acl
        slow_acl = [
            (Allow, 'group:editors', 'edit'),
            DENY_ALL,
            ]
        return slow_acl

user_info = Service(name='users', path='/{username}/info', factory=UserResource)

@user_info.get(permission='view')
def get_info(request):
    ....

@user_info.post(permission='edit')
def set_info(request):
    ....
```

